// Get all rows
const rows = items.map(item => item.json);

// Count occurrences of each email
const emailCounts = {};
rows.forEach(row => {
  const email = (row['Email Address'] || '').trim().toLowerCase();
  if (email) emailCounts[email] = (emailCounts[email] || 0) + 1;
});

// Create updated rows with Duplicate and Status logic
const updatedRows = rows.map(row => {
  const email = (row['Email Address'] || '').trim().toLowerCase();
  const businessAge = (row['How long has your business been operating?'] || '').trim();

  // Mark duplicates
  row['Duplicate?'] = emailCounts[email] > 1 ? 'Duplicate Entry' : '';

  // Startup rejection logic
  // Make sure text matches EXACTLY the dropdown choice in Google Sheets
  if (businessAge.toLowerCase() === 'less than 3 months') {
    row['Status'] = 'Rejected (Startup)'; 
  }

  return row;
});

// Return array of updated rows for bulk update
return updatedRows.map(r => ({ json: r }));

const entryDate = $input.first().json.entry_date; // Expects 'YYYY-MM-DD HH:mm:ss' in UTC

// Convert string to Date in UTC
const [datePart, timePart] = entryDate.split(' ');
const [year, month, day] = datePart.split('-').map(Number);
const [hour, minute, second] = timePart.split(':').map(Number);
// Months are 0-indexed
const utcDate = new Date(Date.UTC(year, month - 1, day, hour, minute, second));

// Format entry_datetime in 'MMMM D, YYYY [at] h:mm a' (using en-CA and custom code)
const options1 = { timeZone: 'America/Toronto', year: 'numeric', month: 'long', day: 'numeric', hour: 'numeric', minute: '2-digit' };
const toLocaleString1 = utcDate.toLocaleString('en-CA', options1).replace(',', ' at');

// Format log_datetime in 'YYYY-MM-DD | HH:mm'
const options2 = { timeZone: 'America/Toronto', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', hour12: false };
const toLocaleString2 = utcDate.toLocaleString('en-CA', options2);
const [dateCA, timeCA] = toLocaleString2.replace(',', '').split(' ');
const logDateTime = dateCA + " | " + timeCA;

return [{
  json: {
    entry_datetime: toLocaleString1,
    log_datetime: logDateTime,
  }
}];
